import { connect }                 from "react-redux";
import { AlertTriangle }           from "react-feather";
import { useForm }                 from "react-hook-form";
import { useLocation, useHistory } from "react-router-dom";

// Import Own Components
import { bindAll, Base64 } from "Helpers";
import toaster             from "Components/Global/Toaster";
import AuthService         from "Store/Services/AuthService";

//Import Own Components
import RestorePassword from "./RestorePassword.jsx";

const RestorePasswordContainer = ({ authService }) => {
	const { search } = useLocation();

	const history   = useHistory();

	const { handleSubmit, ...hookForm } = useForm({
		defaultValues : {
			password  : "",
			password2 : "",
		},
	});

	const handleRestorePassword = (extraProps) => handleSubmit(async data => {

		if (data.password !== data.password2) {
			hookForm.setError("password", {
				type    : "manual",
				message : "Las constraseñas no coinciden.",
			});

			hookForm.setError("password2",    {
				type    : "manual",
				message : "Las constraseñas no coinciden.",
			});
			return;
		}

		const {
			handleStartLoading   = () => {},
			handleFinishLoading  = () => {},
		} = extraProps;

		if (typeof(handleStartLoading) === "function") {
			handleStartLoading();
		}

		const encodedToken = new URLSearchParams(search).get("token");
		const token        = Base64.decode(encodedToken);

		const status = await authService.resetPassword({
			token,
			password : data.password,
		}).unwrap();

		if (typeof(handleStartLoading) === "function") {
			handleFinishLoading();
		}

		if (status === 200) {
			history.push("/auth/restore_completed");
			return;
		}

		toaster.info({
			icon  : AlertTriangle,
			title : "Error",
			body  : "No se ha podido completar la operación con exito, revisa tu conexión a internet.",
		});

	})();

	return (
		<RestorePassword
			delegations={{
				hookForm,
				handleRestorePassword,
			}}
		/>
	);
};

const mapDispatchToProps = bindAll({ AuthService });

export default connect(null, mapDispatchToProps)(RestorePasswordContainer);
