
//Import Own Components
import { Password }   from "Resources/icons";
import AuthForm       from "Components/AuthForm";
import FormInputGroup from "Components/Global/FormInputGroup";

const RestorePassword = ({
	delegations : {
		hookForm,
		handleRestorePassword,
	},
}) => {
	return (
		<div className="RestorePassword">
			<AuthForm
				title="Restablecer Contraseña"
				subTitle="Ingresa una nueva contraseña."
				labelBtn="Restablecer Contraseña"
				handleSumbitForm={handleRestorePassword}
			>
				<FormInputGroup
					type="password"
					name="password"
					label="Nueva Contraseña"
					icon={<Password size={16} />}
					register={hookForm.register}
					errors={hookForm.formState.errors}
					options={{
						required : {
							value   : true,
							message : "Este campo no puede estar vacío.",
						},
						minLength : {
							value   : 8,
							message : "Este compo debe tener mínimo 8 carácteres.",
						},
					}}
				/>
				<FormInputGroup
					type="password"
					name="password2"
					label="Confirmar Contraseña"
					icon={<Password size={16} />}
					register={hookForm.register}
					errors={hookForm.formState.errors}
					options={{
						required : {
							value   : true,
							message : "Este campo no puede estar vacío.",
						},
						minLength : {
							value   : 8,
							message : "Este compo debe tener mínimo 8 carácteres.",
						},
					}}
				/>
			</AuthForm>
		</div>
	);
};

export default RestorePassword;
